import { Wifi, WifiOff, Settings, Clock, Search, Filter, Grid, List, Layers, Cpu, Signal, AlertTriangle, AlertCircle, Play, X, Info, Wrench, Map } from 'lucide-react';
import InteractiveMap from './InteractiveMap';

const API = `${window.location.protocol}//${window.location.host}`;

const Dashboard = ({ user }) => {
  const [machines, setMachines] = useState([]);
  const [selectedMachine, setSelectedMachine] = useState(null);
  const [asnovaLength, setAsnovaLength] = useState("");
  const [activeTab, setActiveTab] = useState('info');
  const [filter, setFilter] = useState('all');
  const [viewMode, setViewMode] = useState('map');
  const [searchQuery, setSearchQuery] = useState('');
  const [wsConnected, setWsConnected] = useState(false);
  const wsRef = useRef(null);
  const reconnectTimeoutRef = useRef(null);

  useEffect(() => {
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = `${protocol}//${window.location.host}/ws/machines`;
    wsRef.current = new WebSocket(wsUrl);
    wsRef.current.onopen = () => { setWsConnected(true); };
    wsRef.current.onmessage = (event) => {
      try { setMachines(JSON.parse(event.data)); } catch (e) {}
    };
    wsRef.current.onclose = () => {
      setWsConnected(false);
      reconnectTimeoutRef.current = setTimeout(() => {
        if (!wsRef.current || wsRef.current.readyState === WebSocket.CLOSED) {
          const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
          wsRef.current = new WebSocket(`${protocol}//${window.location.host}/ws/machines`);
        }
      }, 3000);
    };
    return () => { if (wsRef.current) wsRef.current.close(); };
  }, []);

  useEffect(() => {
    if (wsConnected) return;
    const fetchMachines = async () => {
      try {
        const res = await fetch(`${API}/machines`, {
          headers: { "Authorization": `Bearer ${localStorage.getItem("token")}` }
        });
        if (res.ok) setMachines(await res.json());
      } catch (e) {}
    };
    fetchMachines();
    const interval = setInterval(fetchMachines, 5000);
    return () => clearInterval(interval);
  }, [wsConnected]);

  useEffect(() => {
    if (selectedMachine) {
      fetch(`${API}/machines/${selectedMachine.id}/watch`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${localStorage.getItem("token")}` }
      }).catch(() => {});
    }
  }, [selectedMachine]);

  const handleFillAsnova = async () => {
    if (!asnovaLength || !selectedMachine) return;
    try {
      const res = await fetch(`${API}/machines/${selectedMachine.id}/fill`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("token")}`
        },
        body: JSON.stringify({ initial_asnova_length: parseFloat(asnovaLength), last_operator_id: user.id })
      });
      if (res.ok) {
        alert("Asnova muvaffaqiyatli toldirildi!");
        setSelectedMachine(null);
        setAsnovaLength("");
      }
    } catch (err) { alert("Xatolik yuz berdi"); }
  };

  const handleSourceChange = async (machineId, newSource) => {
    try {
      await fetch(`${API}/machines/${machineId}/source?preferred_source=${newSource}`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${localStorage.getItem('token')}` }
      });
    } catch (err) { alert("Xatolik"); }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'RUNNING': return 'var(--success)';
      case 'OFFLINE': return 'var(--text-muted)';
      case 'ASNOVA_EMPTY': return 'var(--danger)';
      case 'ESP_ONLINE_NO_SIGNAL': return 'var(--warning)';
      default: return 'var(--text-muted)';
    }
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'RUNNING': return 'Ishlamoqda';
      case 'OFFLINE': return 'Offline';
      case 'ASNOVA_EMPTY': return 'Asnova tugagan';
      case 'ESP_ONLINE_NO_SIGNAL': return 'Signal yo\'q';
      default: return 'Noma\'lum';
    }
  };

