{"tool":"newFileCreated","path":"frontend/src/components/Dashboard.jsx","content":"import React, { useState, useEffect } from 'react';
import { Wifi, WifiOff, Map, Layers, Play, AlertTriangle, Signal, X, Clock, Settings, Grid, List } from 'lucide-react';
import InteractiveMap from './InteractiveMap';

const API = `${window.location.protocol}//${window.location.host}`;

const getStatusColor = (status) => {
  switch (status) {
    case 'RUNNING': return '#22c55e';
    case 'OFFLINE': return '#64748b';
    case 'ESP_ONLINE_NO_SIGNAL': return '#f59e0b';
    case 'ASNOVA_EMPTY': return '#ef4444';
    default: return '#94a3b8';
  }
};

const getStatusText = (status) => {
  switch (status) {
    case 'RUNNING': return 'Ishlaydi';
    case 'OFFLINE': return 'Offline';
    case 'ESP_ONLINE_NO_SIGNAL': return 'Signal yo\'q';
    case 'ASNOVA_EMPTY': return 'Bo\'sh';
    default: return status;
  }
};

const Dashboard = ({ user }) => {
  const [machines, setMachines] = useState([]);
  const [filter, setFilter] = useState('all');
  const [viewMode, setViewMode] = useState('map');
  const [wsConnected, setWsConnected] = useState(false);
  const [selectedMachine, setSelectedMachine] = useState(null);
  const [asnovaLength, setAsnovaLength] = useState('');
  const [ws, setWs] = useState(null);

  useEffect(() => {
    fetchMachines();
    const wsUrl = `ws://${window.location.host}/ws`;
    const wsConn = new WebSocket(wsUrl);
    wsConn.onopen = () => setWsConnected(true);
    wsConn.onclose = () => setWsConnected(false);
    wsConn.onmessage = (e) => {
      const data = JSON.parse(e.data);
      setMachines(data);
    };
    setWs(wsConn);
    return () => wsConn.close();
  }, []);

  const fetchMachines = async () => {
    const token = localStorage.getItem('sr_token');
    try {
      const res = await fetch(`${API}/machines`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setMachines(await res.json());
    } catch (e) {}
  };

  const handleFillAsnova = async () => {
    const token = localStorage.getItem('sr_token');
    try {
      await fetch(`${API}/machines/${selectedMachine.id}/fill`, {
        method: 'POST', headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ initial_length: parseFloat(asnovaLength), meters_at_fill: 0 })
      });
      setAsnovaLength('');
      fetchMachines();
    } catch (e) {}
  };

  const filteredMachines = machines.filter(m => {
    if (filter === 'running') return m.status === 'RUNNING';
    if (filter === 'stopped') return m.status === 'ASNOVA_EMPTY';
    if (filter === 'offline') return m.status === 'OFFLINE';
    if (filter === 'warning') return m.status === 'ESP_ONLINE_NO_SIGNAL';
    return true;
  });

  const stats = {
    total: machines.length,
    running: machines.filter(m => m.status === 'RUNNING').length,
    stopped: machines.filter(m => m.status === 'ASNOVA_EMPTY').length,
    warning: machines.filter(m => m.status === 'ESP_ONLINE_NO_SIGNAL').length,
    offline: machines.filter(m => m.status === 'OFFLINE').length,
  };

  return (
    <div className="dashboard">
      <div className="sr-dashboard-header">
        <div className="sr-title">
          <h1>Stanoklar</h1>
          <span className="sr-subtitle">Real-time monitoring</span>
        </div>
        <div className="sr-status">
          {wsConnected ? <span className="sr-connected"><Wifi size={14}/> Online</span> : <span className="sr-disconnected"><WifiOff size={14}/> Offline</span>}
        </div>
      </div>

      <div className="sr-stats">
        <div className="sr-stat"><Layers size={18}/><span className="sr-stat-label">Jami</span><span className="sr-stat-value">{stats.total}</span></div>
        <div className="sr-stat sr-running"><Play size={18}/><span className="sr-stat-label">Ishlaydi</span><span className="sr-stat-value">{stats.running}</span></div>
        <div className="sr-stat sr-stopped"><AlertTriangle size={18}/><span className="sr-stat-label">To'xtagan</span><span className="sr-stat-value">{stats.stopped}</span></div>
        <div className="sr-stat sr-warning"><Signal size={18}/><span className="sr-stat-label">Signal yo'q</span><span className="sr-stat-value">{stats.warning}</span></div>
        <div className="sr-stat sr-offline"><WifiOff size={18}/><span className="sr-stat-label">Offline</span><span className="sr-stat-value">{stats.offline}</span></div>
      </div>

      <div className="sr-controls">
        <div className="sr-filters">
          <button className={`sr-filter-btn ${filter === 'all' ? 'active' : ''}`} onClick={() => setFilter('all')}>Barchasi</button>
          <button className={`sr-filter-btn ${filter === 'running' ? 'active' : ''}`} onClick={() => setFilter('running')}>Ishlaydi</button>
          <button className={`sr-filter-btn ${filter === 'stopped' ? 'active' : ''}`} onClick={() => setFilter('stopped')}>To'xtagan</button>
          <button className={`sr-filter-btn ${filter === 'offline' ? 'active' : ''}`} onClick={() => setFilter('offline')}>Offline</button>
        </div>
        <div className="sr-view-toggle">
          <button className={`sr-view-btn ${viewMode === 'map' ? 'active' : ''}`} onClick={() => setViewMode('map')}><Map size={16}/></button>
          <button className={`sr-view-btn ${viewMode === 'grid' ? 'active' : ''}`} onClick={() => setViewMode('grid')}><Grid size={16}/></button>
          <button className={`sr-view-btn ${viewMode === 'list' ? 'active' : ''}`} onClick={() => setViewMode('list')}><List size={16}/></button>
        </div>
      </div>

      <div className="sr-machines-section">
        {viewMode === 'map' ? (
          <InteractiveMap machines={machines} onSelectMachine={(m) => { setSelectedMachine(m); }} user={user} selectedMachine={selectedMachine} />
        ) : viewMode === 'grid' ? (
          <div className="sr-grid">
            {filteredMachines.map(m => (
              <div key={m.id} className="sr-machine-card" style={{ borderColor: getStatusColor(m.status) }} onClick={() => setSelectedMachine(m)}>
                <div className="sr-machine-id">{m.id}</div>
                <div className="sr-machine-status" style={{ color: getStatusColor(m.status) }}>{getStatusText(m.status)}</div>
                <div className="sr-machine-meters">{m.shift_meters?.toFixed(1) || 0}m</div>
              </div>
            ))}
          </div>
        ) : (
          <div className="sr-list">
            {filteredMachines.map(m => (
              <div key={m.id} className="sr-list-item" style={{ borderLeftColor: getStatusColor(m.status) }} onClick={() => setSelectedMachine(m)}>
                <span className="sr-list-id">{m.id}</span>
                <span className="sr-list-status" style={{ color: getStatusColor(m.status) }}>{getStatusText(m.status)}</span>
                <span className="sr-list-meters">{m.shift_meters?.toFixed(1) || 0}m / {m.remaining?.toFixed(1) || 0}m</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {selectedMachine && (
        <div className="sr-modal">
          <div className="sr-modal-content">
            <button className="sr-close" onClick={() => setSelectedMachine(null)}><X size={18}/></button>
            <h2>Stanok {selectedMachine.id}</h2>
            <div className="sr-modal-info">
              <p><strong>Holat:</strong> <span style={{ color: getStatusColor(selectedMachine.status) }}>{getStatusText(selectedMachine.status)}</span></p>
              <p><strong>Smena metr:</strong> {selectedMachine.shift_meters?.toFixed(2) || 0}m</p>
              <p><strong>Jami metr:</strong> {selectedMachine.meters?.toFixed(2) || 0}m</p>
              <p><strong>Qolgan:</strong> {selectedMachine.remaining?.toFixed(2) || 0}m</p>
              {selectedMachine.status === 'ASNOVA_EMPTY' && (
                <div className="sr-fill-form">
                  <input type="number" placeholder="Asnova uzunligi (m)" value={asnovaLength} onChange={(e) => setAsnovaLength(e.target.value)} />
                  <button onClick={handleFillAsnova}>To'ldirish</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

