{"tool":"newFileCreated","path":"frontend/src/components/UsersPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, X } from 'lucide-react';

const API = `${window.location.protocol}//${window.location.host}`;

const UsersPanel = ({ user }) => {
  const [users, setUsers] = useState([]);
  const [showUserForm, setShowUserForm] = useState(false);
  const [userForm, setUserForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
  const [userError, setUserError] = useState('');
  const token = localStorage.getItem('sr_token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };

  const fetchUsers = async () => {
    try {
      const res = await fetch(`${API}/users`, { headers });
      if (res.ok) {
        const allUsers = await res.json();
        // SR: Admin sees all users except himself, others see only non-admin users
        if (user.role === 'ADMIN') {
          setUsers(allUsers.filter(u => u.id !== user.id));
        } else {
          setUsers(allUsers.filter(u => u.role !== 'ADMIN' && u.id !== user.id));
        }
      }
    } catch (e) {}
  };

  useEffect(() => { fetchUsers(); }, []);

  const handleCreateUser = async () => {
    if (!userForm.username || !userForm.password || !userForm.full_name) {
      setUserError('Barcha maydonlarni toldiring');
      return;
    }
    try {
      const res = await fetch(`${API}/users`, { method: 'POST', headers, body: JSON.stringify(userForm) });
      if (res.ok) {
        setUserForm({ username: '', password: '', full_name: '', role: 'MASTER' });
        setShowUserForm(false);
        setUserError('');
        fetchUsers();
      } else {
        const data = await res.json();
        setUserError(data.detail || 'Xatolik');
      }
    } catch (e) { setUserError('Server xatoligi'); }
  };

  const handleDeleteUser = async (id) => {
    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
      fetchUsers();
    } catch (e) {}
  };

  const roleColors = { MASTER: '#3b82f6', NAZORATCHI: '#22c55e', MECHANIC: '#f59e0b', ELECTRIC: '#06b6d4', UZLAVYAZ: '#a855f7', ADMIN: '#ef4444' };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar</h2>
        {user.role === 'ADMIN' && (
          <button onClick={() => { setShowUserForm(!showUserForm); setUserError(''); }} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
          }}>
            <Plus size={16} /> Yangi Foydalanuvchi
          </button>
        )}
      </div>

      {showUserForm && (
        <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '16px', padding: '1.5rem', marginBottom: '1.5rem' }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Foydalanuvchi</h3>
          {userError && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{userError}</p>}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Username</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }} value={userForm.username} onChange={e => setUserForm({...userForm, username: e.target.value})} placeholder="username" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Parol</label>
              <input className="input-field" type="password" style={{ marginTop: '4px', marginBottom: '0.5rem' }} value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} placeholder="password" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>To'liq Ism</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }} value={userForm.full_name} onChange={e => setUserForm({...userForm, full_name: e.target.value})} placeholder="Ism Familiya" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Rol</label>
              <select className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }} value={userForm.role} onChange={e => setUserForm({...userForm, role: e.target.value})}>
                <option value="MASTER">MASTER</option>
                <option value="NAZORATCHI">NAZORATCHI</option>
                <option value="MECHANIC">MECHANIC</option>
                <option value="ELECTRIC">ELECTRIC</option>
                <option value="UZLAVYAZ">UZLAVYAZ</option>
              </select>
            </div>
          </div>
          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem' }}>
            <button onClick={handleCreateUser} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px', background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700 }}>
              <Save size={14} /> Yaratish
            </button>
            <button onClick={() => { setShowUserForm(false); setUserError(''); }} style={{ display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)', border: '1px solid var(--border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600 }}>
              <X size={14} /> Bekor Qilish
            </button>
          </div>
        </div>
      )}

      <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '16px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid var(--border)' }}>
              <th style={thStyle}>Username</th>
              <th style={thStyle}>Ism</th>
              <th style={thStyle}>Rol</th>
              <th style={thStyle}>Holat</th>
              <th style={thStyle}>Amallar</th>
            </tr>
          </thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                <td style={tdStyle}>{u.username}</td>
                <td style={tdStyle}>{u.full_name}</td>
                <td style={tdStyle}>
                  <span style={{ padding: '3px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700, background: `${roleColors[u.role] || '#64748b'}22`, color: roleColors[u.role] || '#64748b' }}>{u.role}</span>
                </td>
                <td style={tdStyle}>
                  <span style={{ color: u.is_active ? '#22c55e' : '#ef4444', fontSize: '0.8rem' }}>{u.is_active ? 'Faol' : 'Nofaol'}</span>
                </td>
                <td style={tdStyle}>
                  <button onClick={() => handleDeleteUser(u.id)} style={{ padding: '6px', background: '#ef444422', color: '#ef4444', border: '1px solid #ef444444', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center' }}>
                    <Trash2 size={14} />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const thStyle = { padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' };
const tdStyle = { padding: '12px 16px', fontSize: '0.85rem', fontWeight: 500 };

